// ─── 工具函数 ─────────────────────────────────────────────────────────────────
const fmt=(n)=>new Intl.NumberFormat("zh-CN",{minimumFractionDigits:2,maximumFractionDigits:2}).format(Math.abs(n));
const fmtShort=(n)=>{const a=Math.abs(n);return a>=10000?(n/10000).toFixed(1)+"万":Math.round(n).toString();};
const fmtDateLabel=(iso)=>{const d=new Date(iso),t=new Date(),y=new Date(t);y.setDate(t.getDate()-1);if(d.toDateString()===t.toDateString())return"今天";if(d.toDateString()===y.toDateString())return"昨天";return`${d.getMonth()+1}月${d.getDate()}日`;};
const getCatFrom=(cats,type,id)=>(cats[type]||[]).find(c=>c.id===id)||{label:"未知",icon:"❓",color:"#ccc"};
const isImg=(icon)=>typeof icon==="string"&&(icon.startsWith("data:")||icon.startsWith("http"));
const lsGet=(k,def)=>{try{const v=localStorage.getItem(k);if(v==null)return def;const p=JSON.parse(v);return(p==null||p===undefined)?def:p;}catch{return def;}};
const lsSet=(k,v)=>{try{if(v==null){localStorage.removeItem(k);}else{localStorage.setItem(k,JSON.stringify(v));}}catch{}};
const dateToStr=(d)=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
const isActive=(todo,ds)=>{if(!todo.repeat.enabled)return todo.date===ds;const base=new Date(todo.date+"T00:00:00"),tgt=new Date(ds+"T00:00:00");if(tgt<base)return false;const{unit,interval}=todo.repeat;const diffD=Math.round((tgt-base)/86400000);if(unit==="day")return diffD%interval===0;if(unit==="week")return diffD%(interval*7)===0;if(unit==="month"){if(base.getDate()!==tgt.getDate())return false;const m=(tgt.getFullYear()-base.getFullYear())*12+(tgt.getMonth()-base.getMonth());return m%interval===0;}if(unit==="year"){if(base.getMonth()!==tgt.getMonth()||base.getDate()!==tgt.getDate())return false;return(tgt.getFullYear()-base.getFullYear())%interval===0;}return false;};
const getWeekStart=(d)=>{const x=new Date(d);const dow=x.getDay();x.setDate(x.getDate()+(dow===0?-6:1-dow));x.setHours(0,0,0,0);return x;};
const getMonthGrid=(y,m)=>{const first=new Date(y,m,1),last=new Date(y,m+1,0),pad=first.getDay()===0?6:first.getDay()-1,cells=[];for(let i=pad-1;i>=0;i--)cells.push({date:new Date(y,m,-i),in:false});for(let i=1;i<=last.getDate();i++)cells.push({date:new Date(y,m,i),in:true});const rem=42-cells.length;for(let i=1;i<=rem;i++)cells.push({date:new Date(y,m+1,i),in:false});return cells;};

// CSV
const csvEsc=v=>`"${String(v??'').replace(/"/g,'""')}"`;
const parseCSVRow=row=>{const res=[];let cur='',inQ=false;for(let i=0;i<row.length;i++){const c=row[i];if(c==='"'){if(inQ&&row[i+1]==='"'){cur+='"';i++;}else inQ=!inQ;}else if(c===','&&!inQ){res.push(cur);cur='';}else cur+=c;}res.push(cur);return res;};
const parseCSV=text=>{const lines=text.trim().split(/\r?\n/);if(lines.length<2)return[];const hdr=parseCSVRow(lines[0]);return lines.slice(1).map(l=>{const vals=parseCSVRow(l);const obj={};hdr.forEach((h,i)=>obj[h.trim()]=(vals[i]??'').trim());return obj;});};
const dlText=(fname,text,mime='text/csv')=>{const blob=new Blob(['\uFEFF'+text],{type:mime+';charset=utf-8;'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=fname;a.click();URL.revokeObjectURL(url);};
const exportRecs=(recs,accs)=>{const h=['id','type','category','amount','note','accountId','accountName','date'];const rows=recs.map(r=>{const a=accs.find(x=>x.id===r.accountId);return[r.id,r.type,r.category,r.amount,r.note,r.accountId,a?.name??'',r.date].map(csvEsc).join(',');});dlText('账单明细.csv',[h.join(','),...rows].join('\n'));};
const exportTodos=todos=>{const h=['id','title','note','date','done','repeatEnabled','repeatUnit','repeatInterval','completedDates','parentId'];const rows=todos.map(t=>[t.id,t.title,t.note,t.date,t.done,t.repeat.enabled,t.repeat.unit,t.repeat.interval,(t.completedDates||[]).join('|'),t.parentId??''].map(csvEsc).join(','));dlText('待办事项.csv',[h.join(','),...rows].join('\n'));};
const exportJSON=(recs,accs,todos,cats)=>dlText('备份数据.json',JSON.stringify({records:recs,accounts:accs,todos,cats},null,2),'application/json');
const importRecs=text=>parseCSV(text).map(r=>({id:Number(r.id)||Date.now()+Math.random(),type:r.type||'expense',category:r.category||'other',amount:parseFloat(r.amount)||0,note:r.note||'',accountId:Number(r.accountId)||1,date:r.date||new Date().toISOString()})).filter(r=>r.amount>0);
const importTodos=text=>parseCSV(text).map(r=>({id:Number(r.id)||Date.now()+Math.random(),title:r.title||'',note:r.note||'',date:r.date||todayStr(),done:r.done==='true',repeat:{enabled:r.repeatEnabled==='true',unit:r.repeatUnit||'day',interval:Number(r.repeatInterval)||1},completedDates:r.completedDates?r.completedDates.split('|').filter(Boolean):[],parentId:r.parentId||null,children:[]})).filter(r=>r.title);

